 51→:root {
 52→  /* ═══ SURFACES (Ailoom: pure black base) ═══ */
 53→  --bg-base:        #000000;
 54→  --bg-surface:     #0C0D0E;
 55→  --bg-elevated:    #161718;
 56→  --bg-overlay:     #1E1F21;
 57→
 58→  /* ═══ BORDERS (Ailoom: white-alpha based) ═══ */
 59→  --border-default: rgba(255, 255, 255, 0.08);
 60→  --border-subtle:  rgba(255, 255, 255, 0.05);
 61→  --border-strong:  rgba(255, 255, 255, 0.15);
 62→
 63→  /* ═══ TEXTE (Ailoom: white with opacity) ═══ */
 64→  --text-primary:   #FFFFFF;
 65→  --text-secondary: rgba(255, 255, 255, 0.7);
 66→  --text-tertiary:  rgba(255, 255, 255, 0.4);
 67→  --text-disabled:  rgba(255, 255, 255, 0.25);
 68→
 69→  /* ═══ ACCENTS (Ailoom: deep violet #6100DF) ═══ */
 70→  --accent:         #6100DF;
 71→  --accent-hover:   #7B2FE8;
 72→  --accent-subtle:  rgba(97, 0, 223, 0.08);
 73→  --accent-text:    #A855F7;
 74→
 75→  /* ═══ SEMANTIC ═══ */
 76→  --success:        #22C55E;
 77→  --success-subtle: rgba(34, 197, 94, 0.08);
 78→  --warning:        #F59E0B;
 79→  --warning-subtle: rgba(245, 158, 11, 0.08);
 80→  --error:          #EF4444;
 81→  --error-subtle:   rgba(239, 68, 68, 0.08);
 82→
 83→  /* ═══ AI ENGINE IDENTITY ═══ */
 84→  --engine-chatgpt:    #10B981;
 85→  --engine-perplexity: #3B82F6;
 86→  --engine-gemini:     #8B5CF6;
 87→
 88→  /* ═══ GLASSMORPHISM (Ailoom: deeper blacks) ═══ */
 89→  --glass-bg:            rgba(0, 0, 0, 0.8);
 90→  --glass-bg-strong:     rgba(0, 0, 0, 0.9);
 91→  --glass-border:        rgba(255, 255, 255, 0.06);
 92→  --glass-border-hover:  rgba(255, 255, 255, 0.12);
 93→  --glass-surface:       rgba(255, 255, 255, 0.03);
 94→  --glass-surface-hover: rgba(255, 255, 255, 0.06);
 95→  --glass-active:        rgba(255, 255, 255, 0.08);
 96→
 97→  color-scheme: dark;
 98→}
