102→   ═══════════════════════════════════════════════════════════ */
103→
104→html, body, #root {
105→  margin: 0;
106→  padding: 0;
107→  min-height: 100%;
108→  background-color: var(--bg-base);
109→  color: var(--text-secondary);
110→  font-family: 'Hikasami', 'Hikasami Static', 'Inter', system-ui, -apple-system, sans-serif;
111→  font-size: 16px;
112→  line-height: 1.4;
113→  -webkit-font-smoothing: antialiased;
114→  -moz-osx-font-smoothing: grayscale;
115→  text-rendering: optimizeLegibility;
116→}
