118→code, pre, .font-mono, kbd {
119→  font-family: 'Geist Mono', 'SF Mono', Consolas, monospace;
120→}
121→
122→h1, h2, h3, h4, h5, h6 {
123→  font-family: 'Hikasami', 'Hikasami Static', 'Inter', system-ui, sans-serif;
124→  color: var(--text-primary);
125→}
126→
127→h1 {
128→  font-size: clamp(2.5rem, 5vw, 5rem);
129→  font-weight: 400;
130→  letter-spacing: -0.05em;
131→  line-height: 1;
132→}
133→
134→h2 {
135→  font-size: clamp(2rem, 4vw, 4rem);
136→  font-weight: 400;
137→  letter-spacing: -0.04em;
138→  line-height: 1;
139→}
140→
141→h3 {
142→  font-size: 1.25rem;
143→  font-weight: 400;
144→  letter-spacing: 0.01em;
145→  line-height: 1.3;
146→}
147→
148→h4 {
149→  font-size: 1rem;
150→  font-weight: 500;
151→  letter-spacing: 0;
152→  line-height: 1.4;
153→}
