161→/* ═══════════════════════════════════════════════════════════
162→   SCROLLBAR (Ailoom: minimal, dark)
163→   ═══════════════════════════════════════════════════════════ */
164→
165→* {
166→  scrollbar-width: thin;
167→  scrollbar-color: rgba(255, 255, 255, 0.1) transparent;
168→}
169→
170→::-webkit-scrollbar {
171→  width: 6px;
172→  height: 6px;
173→}
174→::-webkit-scrollbar-track {
175→  background: transparent;
176→}
177→::-webkit-scrollbar-thumb {
178→  background: rgba(255, 255, 255, 0.1);
179→  border-radius: 3px;
180→}
181→::-webkit-scrollbar-thumb:hover {
182→  background: rgba(255, 255, 255, 0.2);
183→}
184→::-webkit-scrollbar-corner {
185→  background: transparent;
186→}
187→
188→/* Custom scrollbar for modals */
189→.modal-scroll::-webkit-scrollbar {
190→  width: 6px;
191→}
192→.modal-scroll::-webkit-scrollbar-track {
193→  background: var(--bg-surface);
194→  border-radius: 3px;
195→}
196→.modal-scroll::-webkit-scrollbar-thumb {
197→  background: rgba(255, 255, 255, 0.15);
198→  border-radius: 3px;
199→}
200→.modal-scroll::-webkit-scrollbar-thumb:hover {
201→  background: rgba(255, 255, 255, 0.25);
202→}
203→
204→/* ═══ FOCUS VISIBLE ═══ */
205→*:focus-visible {
206→  outline: 2px solid var(--accent);
207→  outline-offset: 2px;
208→  border-radius: 4px;
209→}
