 1→import React, { useEffect, useState } from 'react';
 2→
 3→interface ScoreRingProps {
 4→  score: number;
 5→  size?: number;
 6→  strokeWidth?: number;
 7→  noAnimation?: boolean;
 8→}
 9→
10→const ScoreRing: React.FC<ScoreRingProps> = ({ score, size = 120, strokeWidth = 8, noAnimation = false }) => {
11→  const [animatedScore, setAnimatedScore] = useState(noAnimation ? score : 0);
12→  const radius = (size - strokeWidth) / 2;
13→  const circumference = radius * 2 * Math.PI;
14→  const offset = circumference - (animatedScore / 100) * circumference;
15→
16→  useEffect(() => {
17→    if (noAnimation) {
18→      setAnimatedScore(score);
19→      return;
20→    }
21→    const timer = setTimeout(() => {
22→      setAnimatedScore(score);
23→    }, 100);
24→    return () => clearTimeout(timer);
25→  }, [score, noAnimation]);
26→
27→  const getColor = (s: number) => {
28→    if (s >= 80) return '#a855f7'; // Purple
29→    if (s >= 60) return '#c084fc'; // Light Purple
30→    if (s >= 40) return '#7c3aed'; // Violet
31→    return '#ef4444'; // Red
32→  };
33→
34→  const color = getColor(animatedScore);
35→
36→  return (
37→    <div className="relative flex items-center justify-center" style={{ width: size, height: size }}>
38→      <svg width={size} height={size} className="transform -rotate-90">
39→        {/* Background Ring */}
40→        <circle
41→          cx={size / 2}
42→          cy={size / 2}
43→          r={radius}
44→          stroke="#ffffff"
45→          strokeOpacity="0.08"
46→          strokeWidth={strokeWidth}
47→          fill="transparent"
48→        />
49→        {/* Progress Ring */}
50→        <circle
51→          cx={size / 2}
52→          cy={size / 2}
53→          r={radius}
54→          stroke={color}
55→          strokeWidth={strokeWidth}
56→          fill="transparent"
57→          strokeDasharray={circumference}
58→          strokeDashoffset={offset}
59→          strokeLinecap="round"
60→          className={noAnimation ? '' : "transition-all duration-1000 ease-out"}
61→        />
62→      </svg>
63→      <div className="absolute flex flex-col items-center">
64→        <span className="text-3xl font-bold font-sans" style={{ color }}>{animatedScore}</span>
65→        <span className="text-xs text-gray-500 uppercase tracking-wider font-medium">AEO Score</span>
66→      </div>
67→    </div>
68→  );
69→};
70→
71→export default ScoreRing;

