**Technical Architecture — Class/Object Design**

```typescript
// ── Data Structures ──

interface Particle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  life: number;       // 0-1, decreases over time
  maxLife: number;
  size: number;
  color: string;       // rgba
  targetNodeIndex?: number; // particle aims for a specific node
}

interface NetworkNode {
  x: number;            // base position (% of canvas width, converted to px)
  y: number;
  baseX: number;        // original position (for parallax reset)
  baseY: number;
  radius: number;       // 3-6
  brightness: number;   // 0-1, current activation level
  targetBrightness: number;
  connections: number[]; // indices of connected nodes
  layer: number;         // depth layer for parallax (0=back, 2=front)
}

interface EnergyPulse {
  fromNode: number;
  toNode: number;
  progress: number;    // 0-1 along the connection
  speed: number;
  size: number;
  opacity: number;
}

interface QueryText {
  text: string;
  x: number;
  y: number;
  charIndex: number;    // typewriter progress
  phase: 'typing' | 'visible' | 'dissolving' | 'done';
  timer: number;
  particles: Particle[]; // particles spawned from dissolving chars
  opacity: number;
}

interface BrandResult {
  name: string;
  x: number;
  y: number;
  cited: boolean;
  opacity: number;
  phase: 'appearing' | 'visible' | 'fading';
  timer: number;
  haloRadius: number;
  vy: number;           // drift velocity (up for cited, down for uncited)
}
```

**Rendering Pipeline (per frame):**

1. Clear canvas (fillRect black)
2. Draw background gradient (subtle radial purple in center)
3. Draw network connections (thin lines, opacity based on node brightness)
4. Draw energy pulses along connections
5. Draw network nodes (circles with glow based on brightness)
6. Draw query texts (left side, with typewriter effect)
7. Draw particles (from dissolved queries, moving toward network)
8. Draw brand results (right side, with halo for cited ones)
9. (HTML overlay renders separately via React)

**Performance Optimizations:**
- Object pooling: reuse particle/query/brand objects instead of creating new ones
- Limit particles to max 200 at any time
- Use canvas `globalCompositeOperation = 'lighter'` for additive glow effects on particles/nodes (switch back to 'source-over' for text)
- Pre-calculate sin/cos tables if needed
- IntersectionObserver: completely stop rAF loop when canvas is off-screen
- Device pixel ratio: set canvas size * devicePixelRatio for crisp rendering, scale context
- prefers-reduced-motion: render a single static frame with all elements visible at their "resting" state

**Component Structure & React Integration**

```tsx
// components/HeroAnimation.tsx

const HeroAnimation: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const animationRef = useRef<number>(0);
  const mouseRef = useRef({ x: 0, y: 0 });
  const isVisibleRef = useRef(true);
  const reducedMotionRef = useRef(false);

  // State refs (not React state — we don't want re-renders)
  const stateRef = useRef<AnimationState>({
    nodes: [],
    particles: [],
    pulses: [],
    queries: [],
    brands: [],
    time: 0,
    nextQueryTime: 0,
    nextBrandTime: 2,
    smoothMouse: { x: 0, y: 0 },
  });

  useEffect(() => {
    // 1. Check prefers-reduced-motion
    const mq = window.matchMedia('(prefers-reduced-motion: reduce)');
    reducedMotionRef.current = mq.matches;
    const onMotionChange = (e: MediaQueryListEvent) => {
      reducedMotionRef.current = e.matches;
    };
    mq.addEventListener('change', onMotionChange);

    // 2. Setup canvas with DPR
    const canvas = canvasRef.current!;
    const ctx = canvas.getContext('2d')!;
    const resize = () => {
      const rect = containerRef.current!.getBoundingClientRect();
      const dpr = window.devicePixelRatio || 1;
      canvas.width = rect.width * dpr;
      canvas.height = rect.height * dpr;
      canvas.style.width = rect.width + 'px';
      canvas.style.height = rect.height + 'px';
      ctx.scale(dpr, dpr);
      // Recalculate node positions based on new dimensions
      initializeNodes(stateRef.current, rect.width, rect.height);
    };
    resize();
    window.addEventListener('resize', resize);

    // 3. Mouse tracking
    const onMouseMove = (e: MouseEvent) => {
      const rect = canvas.getBoundingClientRect();
      mouseRef.current = {
        x: (e.clientX - rect.left) / rect.width - 0.5,  // -0.5 to 0.5
        y: (e.clientY - rect.top) / rect.height - 0.5,
      };
    };
    canvas.addEventListener('mousemove', onMouseMove);

    // 4. Intersection Observer
    const observer = new IntersectionObserver(
      ([entry]) => { isVisibleRef.current = entry.isIntersecting; },
      { threshold: 0.1 }
    );
    observer.observe(canvas);

    // 5. Initialize state
    const rect = containerRef.current!.getBoundingClientRect();
    initializeNodes(stateRef.current, rect.width, rect.height);

    // 6. Animation loop
    let lastTime = 0;
    const loop = (timestamp: number) => {
      const dt = Math.min((timestamp - lastTime) / 1000, 0.05); // cap at 50ms
      lastTime = timestamp;

      if (isVisibleRef.current) {
        if (reducedMotionRef.current) {
          renderStaticFrame(ctx, stateRef.current, rect.width, rect.height);
        } else {
          update(stateRef.current, dt, mouseRef.current, rect.width, rect.height);
          render(ctx, stateRef.current, rect.width, rect.height);
        }
      }

      animationRef.current = requestAnimationFrame(loop);
    };
    animationRef.current = requestAnimationFrame(loop);

    // 7. Cleanup
    return () => {
      cancelAnimationFrame(animationRef.current);
      observer.disconnect();
      window.removeEventListener('resize', resize);
      canvas.removeEventListener('mousemove', onMouseMove);
      mq.removeEventListener('change', onMotionChange);
    };
  }, []);

  return (
    <div ref={containerRef} className="relative w-full mb-32" style={{ height: '560px' }}>
      <canvas ref={canvasRef} className="absolute inset-0 w-full h-full" />
      {/* Glassmorphism overlay */}
      <div className="absolute bottom-0 left-0 right-0 ...">
        ...overlay text...
      </div>
    </div>
  );
};
```

**Key Design Decisions:**
1. All animation state lives in `useRef`, NOT `useState` — no re-renders during animation
2. Canvas dimensions recalculated on resize; nodes repositioned proportionally
3. Delta-time based updates for consistent speed regardless of frame rate
4. dt capped at 50ms to prevent jumps when tab is backgrounded
5. Reduced motion shows a beautiful static composition
6. The overlay is real HTML for accessibility (screen readers, focus, clicks)

